<?php $this->extend('layouts.public'); ?><?php $this->section('content'); ?><section class="section"><div class="container" style="max-width:900px"><h1><?= $listing?'Edit trailer':'Add trailer' ?></h1><?php $this->include('partials.provider-nav',['active'=>'trailer-listings']); ?><form class="card" method="post" action="<?= e(url('provider/trailer-listings/save')) ?>"><?= csrf_field() ?><?php if($listing): ?><input type="hidden" name="id" value="<?= (int)$listing['id'] ?>"><?php endif; ?><div class="form-group"><label for="title">Listing title</label><input id="title" name="title" required maxlength="190" value="<?= e_attr($listing['title']??'') ?>"></div><div class="grid grid-2"><div class="form-group"><label for="trailer_type">Trailer type</label><select id="trailer_type" name="trailer_type" required><?php foreach($types as $type): ?><option value="<?= e_attr($type) ?>" <?= ($listing['trailer_type']??'')===$type?'selected':'' ?>><?= $this->e(ucwords(str_replace('_',' ',$type))) ?></option><?php endforeach; ?></select></div><div class="form-group"><label for="listing_type">Availability</label><select id="listing_type" name="listing_type"><?php foreach(['new'=>'New','used'=>'Used','hire'=>'Hire'] as $key=>$label): ?><option value="<?= $key ?>" <?= ($listing['listing_type']??'used')===$key?'selected':'' ?>><?= $label ?></option><?php endforeach; ?></select></div></div><div class="form-group"><label for="description">Description</label><textarea id="description" name="description" required rows="6"><?= $this->e($listing['description']??'') ?></textarea></div><div class="grid grid-3"><?php foreach(['make'=>'Make','model'=>'Model','model_year'=>'Year','price_aud'=>'Price (AUD)','atm_kg'=>'ATM (kg)','tare_kg'=>'Tare (kg)','location_text'=>'Location'] as $key=>$label): ?><div class="form-group"><label for="<?= $key ?>"><?= $label ?></label><input id="<?= $key ?>" name="<?= $key ?>" <?= in_array($key,['model_year','price_aud','atm_kg','tare_kg'],true)?'type="number" min="0" step="0.1"':'' ?> value="<?= e_attr((string)($listing[$key]??'')) ?>"></div><?php endforeach; ?></div><button class="btn btn-primary" type="submit">Save and submit</button></form></div></section><?php $this->endSection(); ?>
